import 'package:flutter/material.dart';
import 'package:google_fonts/google_fonts.dart';

import 'theme.dart';

class LoginScreen extends StatefulWidget {
  const LoginScreen({super.key});

  @override
  State<LoginScreen> createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> {
  final _email = TextEditingController();
  final _password = TextEditingController();
  bool _rememberMe = false;

  InputDecoration _fieldDecoration(String hint) {
    return InputDecoration(
      hintText: hint,
      filled: true,
      fillColor: AppTheme.surface,
      contentPadding: const EdgeInsets.symmetric(horizontal: 12, vertical: 14),
      enabledBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(8),
        borderSide: const BorderSide(color: Color(0xFFD1D1D6)),
      ),
      focusedBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(8),
        borderSide: const BorderSide(color: AppTheme.brandPrimary),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppTheme.surface,
      body: SafeArea(
        child: SingleChildScrollView(
          padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 32),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              Center(
                child: Image.asset('assets/logo.png', width: 96, height: 96),
              ),
              const SizedBox(height: 24),
              Text(
                'Welcome back',
                textAlign: TextAlign.center,
                style: GoogleFonts.spaceGrotesk(
                  fontSize: AppTheme.headingSize,
                  fontWeight: FontWeight.w700,
                  color: AppTheme.brandInk,
                ),
              ),
              const SizedBox(height: 24),
              SizedBox(
                height: AppTheme.inputHeight,
                child: TextField(
                  controller: _email,
                  decoration: _fieldDecoration('Email'),
                ),
              ),
              const SizedBox(height: 12),
              SizedBox(
                height: AppTheme.inputHeight,
                child: TextField(
                  controller: _password,
                  obscureText: true,
                  decoration: _fieldDecoration('Password'),
                ),
              ),
              const SizedBox(height: 24),
              Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  const Text(
                    'Remember me',
                    style: TextStyle(
                      fontSize: AppTheme.bodySize,
                      color: AppTheme.brandInk,
                    ),
                  ),
                  Switch(
                    value: _rememberMe,
                    activeColor: const Color(0xFF34C759),
                    onChanged: (v) => setState(() => _rememberMe = v),
                  ),
                ],
              ),
              const SizedBox(height: 24),
              ElevatedButton(
                style: ElevatedButton.styleFrom(
                  backgroundColor: AppTheme.brandPrimary,
                  foregroundColor: Colors.white,
                  elevation: 0,
                  padding: const EdgeInsets.symmetric(vertical: 16),
                  shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(AppTheme.radiusButton),
                  ),
                ),
                onPressed: _signIn,
                child: const Text(
                  'Sign In',
                  style: TextStyle(
                    fontSize: AppTheme.bodySize,
                    fontWeight: FontWeight.w600,
                  ),
                ),
              ),
              const SizedBox(height: 24),
              Center(
                child: Text(
                  'Forgot password?',
                  style: const TextStyle(
                    fontSize: 13,
                    color: AppTheme.textSecondary,
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  void _signIn() {}
}

import 'package:flutter/material.dart';

// Transferred from sample-ios/Sources/Theme.swift by Unitem (iOS is the source of truth).

class AppTheme {
  static const Color brandPrimary = Color(0xFFE11D48);
  static const Color brandInk = Color(0xFF1A1B4B);
  static const Color textSecondary = Color(0xFF8A8BB3);
  static const Color surface = Color(0xFFFFFFFF);
  static const double inputHeight = 52;
  static const double radiusButton = 12;
  static const double spacingUnit = 8;
  static const double headingSize = 28;
  static const double bodySize = 17;
}
